module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output dout_parallel,
    output dout_valid
);
    reg [3:0] cnt;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) cnt <= 4'b0;
        else if (din_valid) cnt <= cnt + 1;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) dout_parallel <= 8'b0;
        else if (din_valid) dout_parallel <= {dout_parallel[6:0], din_serial};
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) dout_valid <= 1'b0;
        else if (cnt == 4'b1111) dout_valid <= 1'b1;
        else dout_valid <= 1'b0;
    end
endmodule
